const domain = $('Loop Domains').first().json.domain;
const staticData = this.getWorkflowStaticData('global');
staticData.results ??= [];

// n8n doesn't expose SSL cert info directly from httpRequest,
// but if the request succeeded, the cert is valid.
// For actual expiry checking, we'd need a Code node with TLS.
const success = !$json.error;

staticData.results.push({
  domain,
  valid: success,
  error: $json.error || null
});

return [{ json: { domain, valid: success } }];

const staticData = this.getWorkflowStaticData('global');
const results = staticData.results || [];
staticData.results = []; // reset

const failed = results.filter(r => !r.valid);
const passed = results.filter(r => r.valid);

const summary = [
  `✅ **${passed.length}** domains OK`,
  failed.length > 0 ? `❌ **${failed.length}** domains FAILED:\n${failed.map(f => `  • ${f.domain}: ${f.error || 'connection failed'}`).join('\n')}` : ''
].filter(Boolean).join('\n\n');

return [{ json: {
  summary,
  hasFailed: failed.length > 0,
  failedCount: failed.length,
  passedCount: passed.length,
  timestamp: new Date().toISOString()
}}];
